// Verify HMAC-SHA256 signature from the Strategy Radar app.
// Header: X-Signature-256: sha256=<hex>
// Secret: N8N_WEBHOOK_SECRET (set as Static Data or hardcoded for PoC)

const crypto = require('crypto');

// Retrieve secret from n8n Static Data (workflow-level).
// For PoC: replace $getWorkflowStaticData('global').N8N_WEBHOOK_SECRET
// with the literal secret string if Static Data is not available on your plan.
const workflowData = $getWorkflowStaticData('global');
const secret = workflowData.N8N_WEBHOOK_SECRET || process.env.N8N_WEBHOOK_SECRET || '';

if (!secret) {
  throw new Error('N8N_WEBHOOK_SECRET is not configured. Set it in workflow Static Data.');
}

const body = $input.first().json.body;
const rawBody = typeof body === 'string' ? body : JSON.stringify(body);
const sigHeader = $input.first().headers['x-signature-256'] || '';

// sigHeader format: 'sha256=<hexdigest>'
const expectedPrefix = 'sha256=';
if (!sigHeader.startsWith(expectedPrefix)) {
  throw new Error('Missing or malformed X-Signature-256 header');
}
const receivedSig = sigHeader.slice(expectedPrefix.length);

const computedSig = crypto
  .createHmac('sha256', secret)
  .update(rawBody, 'utf8')
  .digest('hex');

// Constant-time comparison
if (!crypto.timingSafeEqual(Buffer.from(receivedSig, 'hex'), Buffer.from(computedSig, 'hex'))) {
  throw new Error('HMAC signature mismatch — request rejected');
}

// Extract and validate required fields
const payload = typeof body === 'string' ? JSON.parse(body) : body;
const required = ['jobId', 'callbackUrl', 'publicationFileUrl', 'naceDivision'];
for (const field of required) {
  if (!payload[field]) throw new Error(`Missing required field: ${field}`);
}

return [{ json: payload }];

// Detect file type from the URL and route accordingly.
// Returns: { isPdf: boolean, isDocx: boolean, fileUrl: string, ...passthrough }
const input = $input.first().json;
const fileUrl = input.publicationFileUrl || '';
const lowerUrl = fileUrl.toLowerCase().split('?')[0]; // strip query params

const isPdf = lowerUrl.endsWith('.pdf');
const isDocx = lowerUrl.endsWith('.docx') || lowerUrl.endsWith('.doc');

if (!isPdf && !isDocx) {
  throw new Error(`Unsupported file type in URL: ${fileUrl}. Expected .pdf or .docx`);
}

return [{
  json: {
    ...input,
    isPdf,
    isDocx,
  }
}];

// Extract plain text from a PDF binary.
// n8n Cloud does not bundle a native PDF extraction node by default.
// This implementation uses the binary data from the Fetch node and
// calls a lightweight text extraction approach.
//
// IMPORTANT: This Code node receives the binary output from 'Fetch Publication File'.
// n8n passes binary data as a Buffer accessible via $binary.
// We use a simple regex-based text extraction that works for text-based PDFs.
// For scanned PDFs (image-only), this returns empty text — acceptable for PoC.

const binaryData = $input.first().binary?.data;
const payload = $input.first().json;

let extractedText = '';

if (binaryData) {
  // Get the buffer
  const buf = Buffer.from(binaryData, 'base64');
  const raw = buf.toString('latin1');

  // Extract text streams from PDF (works for text-based PDFs)
  // Pattern: content between BT (begin text) and ET (end text) markers
  const streams = [];
  const streamRegex = /stream[\r\n]([\s\S]*?)[\r\n]endstream/g;
  let match;
  while ((match = streamRegex.exec(raw)) !== null) {
    streams.push(match[1]);
  }

  // Extract printable ASCII text from each stream
  const textParts = [];
  for (const stream of streams) {
    // Pull out text between parentheses (PDF text operators)
    const textInParens = stream.match(/\(([^)]{3,})\)/g) || [];
    for (const t of textInParens) {
      const cleaned = t.slice(1, -1)
        .replace(/\\n/g, ' ')
        .replace(/\\r/g, ' ')
        .replace(/\\t/g, ' ')
        .replace(/\\\\/g, '\\')
        .replace(/\\\(/g, '(')
        .replace(/\\\)/g, ')')
        .trim();
      if (cleaned.length > 2) textParts.push(cleaned);
    }
  }
  extractedText = textParts.join(' ');
}

// Limit to ~50k characters to stay within model context
if (extractedText.length > 50000) {
  extractedText = extractedText.slice(0, 50000) + '\n\n[Dokument byl zkrácen — zobrazena první část.]';
}

if (!extractedText || extractedText.trim().length < 50) {
  extractedText = '[Extrakce textu se nezdařila — dokument může být skenovaný nebo v nevhodném formátu. Vygeneruj přehled na základě NACE sektoru bez specifického textu publikace.]';
}

return [{
  json: {
    ...payload,
    extractedText,
    extractionMethod: 'pdf-stream-parse',
  }
}];

// Extract plain text from a DOCX binary.
// DOCX files are ZIP archives containing word/document.xml.
// This implementation extracts XML content and strips tags.

const binaryData = $input.first().binary?.data;
const payload = $input.first().json;

let extractedText = '';

if (binaryData) {
  const buf = Buffer.from(binaryData, 'base64');

  // DOCX is a ZIP. Look for the document.xml content in the raw bytes.
  // Simple approach: find XML text between <w:t> tags.
  const raw = buf.toString('utf8', 0, Math.min(buf.length, 2000000)); // 2MB cap

  // Extract all <w:t> text runs (standard DOCX text element)
  const textRuns = raw.match(/<w:t[^>]*>([^<]+)<\/w:t>/g) || [];
  const parts = textRuns.map(t => {
    const inner = t.replace(/<[^>]+>/g, '');
    return inner;
  }).filter(t => t.trim().length > 0);

  extractedText = parts.join(' ');
}

// Limit to ~50k characters
if (extractedText.length > 50000) {
  extractedText = extractedText.slice(0, 50000) + '\n\n[Dokument byl zkrácen — zobrazena první část.]';
}

if (!extractedText || extractedText.trim().length < 50) {
  extractedText = '[Extrakce textu se nezdařila — DOCX dokument nelze přečíst. Vygeneruj přehled na základě NACE sektoru bez specifického textu publikace.]';
}

return [{
  json: {
    ...payload,
    extractedText,
    extractionMethod: 'docx-wt-parse',
  }
}];

// Merge the two extraction branches back into a single item.
// Both branches (PDF and DOCX) produce the same output shape.
return $input.all();

// Extract the opener text from Claude's API response and attach to payload.
const claudeResponse = $input.first().json;
const prevData = $('Merge Extraction').first().json;

let openerMarkdown = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  openerMarkdown = claudeResponse.content[0].text || '';
}

if (!openerMarkdown) {
  throw new Error('Claude Call 1 returned empty opener text');
}

return [{
  json: {
    ...prevData,
    openerMarkdown,
  }
}];

