          "observations": {
            "type": "array",
            "minItems": 3,
            "maxItems": 3,
            "items": {
              "type": "object",
              "properties": {
                "headline": { "type": "string" },
                "body": { "type": "string" },
                "time_horizon": { "type": "string", "enum": ["Okamžitě", "Do 3 měsíců", "Do 12 měsíců", "Více než rok"] },
                "is_email_teaser": { "type": "boolean" }
              },
              "required": ["headline", "body", "time_horizon", "is_email_teaser"]
            }
          },
          "closing_actions": {
            "type": "array",
            "minItems": 3,
            "maxItems": 3,
            "items": {
              "type": "object",
              "properties": {
                "action_text": { "type": "string" },
                "time_horizon": { "type": "string", "enum": ["Okamžitě", "Do 3 měsíců", "Do 12 měsíců", "Více než rok"] },
                "category": { "type": "string", "enum": ["ziskovost", "naklady-produktivita", "efektivita-kapitalu", "rust-trzni-pozice"] },
                "paired_observation_index": { "type": "integer", "minimum": 0, "maximum": 2 }
              },
              "required": ["action_text", "time_horizon", "category", "paired_observation_index"]
            }
          }
        },
        "required": ["observations", "closing_actions"]
      }
    }
  ],
  "tool_choice": { "type": "tool", "name": "structured_brief_content" }
