// Extract structured output from Claude's tool_use response.
// When tool_choice: { type: 'tool' } is set, Claude returns a tool_use block.
const claudeResponse = $input.first().json;
const prevData = $('Extract Opener').first().json;

let observations = [];
let closingActions = [];

// Find the tool_use content block
const content = claudeResponse.content || [];
const toolBlock = content.find(b => b.type === 'tool_use' && b.name === 'structured_brief_content');

if (toolBlock && toolBlock.input) {
  observations = toolBlock.input.observations || [];
  closingActions = toolBlock.input.closing_actions || [];
} else {
  // Fallback: try to parse the text content as JSON
  const textBlock = content.find(b => b.type === 'text');
  if (textBlock && textBlock.text) {
    try {
      const parsed = JSON.parse(textBlock.text.trim());
      observations = parsed.observations || [];
      closingActions = parsed.closing_actions || [];
    } catch {
      throw new Error('Claude Call 2: could not extract structured output from tool_use or text response');
    }
  } else {
    throw new Error('Claude Call 2: no tool_use block and no text block in response');
  }
}

// Validate counts
if (observations.length !== 3) {
  throw new Error(`Expected 3 observations, got ${observations.length}`);
}
if (closingActions.length !== 3) {
  throw new Error(`Expected 3 closing_actions, got ${closingActions.length}`);
}

// Validate time_horizon values
const validHorizons = ['Okamžitě', 'Do 3 měsíců', 'Do 12 měsíců', 'Více než rok'];
for (const obs of observations) {
  if (!validHorizons.includes(obs.time_horizon)) {
    throw new Error(`Invalid time_horizon in observation: ${obs.time_horizon}`);
  }
}
for (const action of closingActions) {
  if (!validHorizons.includes(action.time_horizon)) {
    throw new Error(`Invalid time_horizon in action: ${action.time_horizon}`);
  }
  if (action.paired_observation_index < 0 || action.paired_observation_index > 2) {
    throw new Error(`paired_observation_index out of range: ${action.paired_observation_index}`);
  }
}

return [{
  json: {
    ...prevData,
    observations,
    closingActions,
  }
}];

// Compose the final draft payload per the n8n callback contract.
// docs/engineering/n8n-integration.md §5

const data = $input.first().json;

// Build filename stem from file_path for the source attribution
const filePath = data.file_path || data.publicationFileUrl || '';
const fileNameStem = filePath.split('/').pop()?.split('?')[0]?.replace(/\.[^.]+$/, '') || 'publikace';

// Build Czech month-year string
const now = new Date();
const czechMonths = ['Leden','Únor','Březen','Duben','Květen','Červen','Červenec','Srpen','Září','Říjen','Listopad','Prosinec'];
const publicationMonth = `${czechMonths[now.getMonth()]} ${now.getFullYear()}`;

// ISO month for the callback contract field
const isoMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

const draft = {
  title: `Sektorová analýza — NACE ${data.naceDivision} — ${publicationMonth}`,
  publication_month: isoMonth,
  publication: {
    heading: 'Sektorová analýza',
    opener_markdown: data.openerMarkdown,
    full_text_markdown: data.extractedText || '',
    source: `Ekonomické a strategické analýzy České spořitelny — ${fileNameStem}, ${publicationMonth}`,
  },
  observations: data.observations,
  closing_actions: data.closingActions,
};

const callbackPayload = {
  jobId: data.jobId,
  status: 'done',
  draft,
};

return [{
  json: {
    callbackUrl: data.callbackUrl,
    callbackPayload,
    jobId: data.jobId,
  }
}];

// Sign the callback payload with HMAC-SHA256 using N8N_CALLBACK_SECRET.
// Produces the X-Signature-256 header value.
const crypto = require('crypto');

const workflowData = $getWorkflowStaticData('global');
const secret = workflowData.N8N_CALLBACK_SECRET || process.env.N8N_CALLBACK_SECRET || '';

if (!secret) {
  throw new Error('N8N_CALLBACK_SECRET is not configured. Set it in workflow Static Data.');
}

const data = $input.first().json;
const bodyStr = JSON.stringify(data.callbackPayload);
const sig = crypto.createHmac('sha256', secret).update(bodyStr, 'utf8').digest('hex');

return [{
  json: {
    callbackUrl: data.callbackUrl,
    callbackBody: bodyStr,
    signatureHeader: `sha256=${sig}`,
    jobId: data.jobId,
  }
}];

// Error handler — fires when any upstream node throws.
// Attempts to send a failure callback to the app so the job can be marked failed.
const crypto = require('crypto');

const workflowData = $getWorkflowStaticData('global');
const secret = workflowData.N8N_CALLBACK_SECRET || process.env.N8N_CALLBACK_SECRET || '';

// Try to recover the original payload to get callbackUrl and jobId
let callbackUrl = '';
let jobId = '';
try {
  // Walk back through available node data to find the webhook payload
  const webhookData = $('Verify HMAC').first()?.json;
  callbackUrl = webhookData?.callbackUrl || '';
  jobId = webhookData?.jobId || '';
} catch {
  // Cannot recover — log and exit
  console.error('[error-handler] Could not recover callbackUrl or jobId from upstream nodes');
  return [{ json: { handled: false, reason: 'could not recover callback context' } }];
}

if (!callbackUrl || !jobId) {
  return [{ json: { handled: false, reason: 'missing callbackUrl or jobId' } }];
}

const errorMessage = $input.first()?.json?.error?.message || 'Unknown error in n8n workflow';

const failPayload = {
  jobId,
  status: 'failed',
  error: errorMessage,
};

const bodyStr = JSON.stringify(failPayload);
let signatureHeader = '';
if (secret) {
  const sig = crypto.createHmac('sha256', secret).update(bodyStr, 'utf8').digest('hex');
  signatureHeader = `sha256=${sig}`;
}

return [{
  json: {
    callbackUrl,
    callbackBody: bodyStr,
    signatureHeader,
  }
}];
